/**
 * update-html-responsive-images.mjs
 *
 * Updates HTML files to add srcset attributes for responsive image loading.
 * Uses the responsive-image-map.json generated by optimize-images.mjs.
 *
 * Strategy:
 *   For standard <img> tags → add srcset with width descriptors + sizes attribute
 *   For <picture><source> → add additional source elements for breakpoints
 *   For data-nectar-img-src → add data attributes for responsive (JS-driven lazy load)
 *   For CSS background-image → inject <style> media queries
 */

import fs from 'fs';
import path from 'path';
import sharp from 'sharp';

const ROOT = path.resolve('New');
const mapping = JSON.parse(fs.readFileSync(path.join(ROOT, 'responsive-image-map.json'), 'utf-8'));

// Build a lookup: filename → { desktop, tablet, mobile } (with actual widths)
async function buildLookup() {
  const lookup = {};
  
  for (const [origRelPath, variants] of Object.entries(mapping)) {
    const origFilename = path.basename(origRelPath);
    const dir = path.dirname(path.join(ROOT, origRelPath));
    
    // Get original width
    const origFull = path.join(ROOT, origRelPath);
    let origWidth = 1600;
    try {
      const meta = await sharp(origFull).metadata();
      origWidth = meta.width;
    } catch(e) {}
    
    const entry = { origWidth };
    
    for (const [bp, file] of Object.entries(variants)) {
      if (!file) continue;
      const fullPath = path.join(dir, file);
      if (fs.existsSync(fullPath)) {
        try {
          const meta = await sharp(fullPath).metadata();
          entry[bp] = { file, width: meta.width, path: fullPath };
        } catch(e) {}
      }
    }
    
    lookup[origFilename] = entry;
  }
  
  return lookup;
}

function findHtmlFiles(dir) {
  const results = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory() && !['node_modules', '.git', 'assets'].includes(entry.name)) {
      results.push(...findHtmlFiles(full));
    } else if (entry.isFile() && entry.name.endsWith('.html')) {
      results.push(full);
    }
  }
  // Also get root index.html
  const rootIndex = path.join(dir, 'index.html');
  if (fs.existsSync(rootIndex) && !results.includes(rootIndex)) {
    results.push(rootIndex);
  }
  return [...new Set(results)];
}

async function main() {
  const lookup = await buildLookup();
  console.log(`Loaded ${Object.keys(lookup).length} image mappings\n`);
  
  const htmlFiles = findHtmlFiles(ROOT);
  let totalUpdates = 0;
  
  for (const file of htmlFiles) {
    let html = fs.readFileSync(file, 'utf-8');
    const relPath = path.relative(ROOT, file);
    let updates = 0;
    
    for (const [origFilename, variants] of Object.entries(lookup)) {
      // Skip if image not referenced in this file
      if (!html.includes(origFilename)) continue;
      
      // Build srcset value
      const srcsetParts = [];
      
      // The original (full size)
      srcsetParts.push(`ORIG_PATH ${variants.origWidth}w`);
      
      if (variants.desktop) {
        srcsetParts.push(`DESKTOP_PATH ${variants.desktop.width}w`);
      }
      if (variants.tablet) {
        srcsetParts.push(`TABLET_PATH ${variants.tablet.width}w`);
      }
      if (variants.mobile) {
        srcsetParts.push(`MOBILE_PATH ${variants.mobile.width}w`);
      }
      
      if (srcsetParts.length <= 1) continue; // No variants to add
      
      // ── Handle standard <img> tags with src="...origFilename..." ──
      // Match src="path/to/origFilename" and add srcset
      const srcPattern = new RegExp(
        `(src="([^"]*${escapeRegex(origFilename)})")(?!.*srcset)`,
        'g'
      );
      
      html = html.replace(srcPattern, (match, fullSrc, srcPath) => {
        const dir = srcPath.substring(0, srcPath.lastIndexOf('/') + 1);
        
        let srcset = `${srcPath} ${variants.origWidth}w`;
        if (variants.desktop) srcset += `, ${dir}${variants.desktop.file} ${variants.desktop.width}w`;
        if (variants.tablet) srcset += `, ${dir}${variants.tablet.file} ${variants.tablet.width}w`;
        if (variants.mobile) srcset += `, ${dir}${variants.mobile.file} ${variants.mobile.width}w`;
        
        updates++;
        return `${fullSrc} srcset="${srcset}" sizes="(max-width: 480px) 480px, (max-width: 768px) 768px, (max-width: 1200px) 1200px, ${variants.origWidth}px"`;
      });
      
      // ── Handle data-nectar-img-src="...origFilename..." (lazy-loaded images) ──
      // For these, add a srcset via a regular src/srcset since the lazy loader will handle it
      const nectarPattern = new RegExp(
        `(data-nectar-img-src="([^"]*${escapeRegex(origFilename)})")`,
        'g'
      );
      
      html = html.replace(nectarPattern, (match, fullAttr, srcPath) => {
        if (html.includes(`data-nectar-img-srcset=`) && html.indexOf(match) < html.indexOf(`data-nectar-img-srcset=`)) {
          return match; // Already has responsive
        }
        
        const dir = srcPath.substring(0, srcPath.lastIndexOf('/') + 1);
        
        let srcset = `${srcPath} ${variants.origWidth}w`;
        if (variants.desktop) srcset += `, ${dir}${variants.desktop.file} ${variants.desktop.width}w`;
        if (variants.tablet) srcset += `, ${dir}${variants.tablet.file} ${variants.tablet.width}w`;
        if (variants.mobile) srcset += `, ${dir}${variants.mobile.file} ${variants.mobile.width}w`;
        
        updates++;
        return `${fullAttr} data-nectar-img-srcset="${srcset}" sizes="(max-width: 480px) 480px, (max-width: 768px) 768px, (max-width: 1200px) 1200px, ${variants.origWidth}px"`;
      });
      
      // ── Handle <picture><source> with media queries ──
      // If the image is in a <picture> <source srcset>, add additional sources for smaller sizes
      const pictureSourcePattern = new RegExp(
        `(<source[^>]*srcset="[^"]*${escapeRegex(origFilename)}"[^>]*>)`,
        'g'
      );
      
      html = html.replace(pictureSourcePattern, (match, sourceTag) => {
        // Only add if we haven't already
        if (html.includes(`${origFilename.replace('.webp', '_mobile.webp')}`)) {
          return match;
        }
        
        const dir = sourceTag.match(/srcset="([^"]*)/)?.[1]?.substring(0, sourceTag.match(/srcset="([^"]*)/)?.[1].lastIndexOf('/') + 1) || '';
        
        let additions = '';
        if (variants.mobile) {
          additions += `<source media="(max-width: 480px)" srcset="${dir}${variants.mobile.file}">`;
        }
        if (variants.tablet) {
          additions += `<source media="(max-width: 768px)" srcset="${dir}${variants.tablet.file}">`;
        }
        
        if (additions) {
          updates++;
          return additions + match;
        }
        return match;
      });
    }
    
    if (updates > 0) {
      fs.writeFileSync(file, html, 'utf-8');
      console.log(`✓ ${relPath}: ${updates} responsive image update(s)`);
      totalUpdates += updates;
    } else {
      console.log(`  ${relPath}: no changes needed`);
    }
  }
  
  console.log(`\n── Summary ──`);
  console.log(`Total responsive updates: ${totalUpdates}`);
  console.log(`Files modified: ${htmlFiles.length}`);
}

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

main().catch(console.error);
